import{_ as e}from"./chunks/cloudflare api token截图.cXTahxtC.js";import{_ as l}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as o,o as i,c as r,a2 as t}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Cloudflare API Token","description":"","frontmatter":{},"headers":[],"relativePath":"ar-SA/Safety/cloudflare-api-token.md","filePath":"ar-SA/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),d={name:"ar-SA/Safety/cloudflare-api-token.md"};function n(p,a,c,u,h,s){return i(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="cloudflare-api-token" tabindex="-1">Cloudflare API Token <a class="header-anchor" href="#cloudflare-api-token" aria-label="Permalink to &quot;Cloudflare API Token&quot;">​</a></h1><p>تسمح بيانات Cloudflare API لـ ImgBed بتنظيف كاش Cloudflare CDN بعد تغيّر الملفات.</p><p><img src="'+e+'" alt="إعدادات Cloudflare API Token" loading="lazy"></p><h2 id="أين-تضبطه؟" tabindex="-1">أين تضبطه؟ <a class="header-anchor" href="#أين-تضبطه؟" aria-label="Permalink to &quot;أين تضبطه؟&quot;">​</a></h2><p>افتح لوحة الإدارة، ثم انتقل إلى:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Cloudflare API Token</span></span></code></pre></div><p>تحتاج إلى ملء:</p><ul><li>Zone ID</li><li>Account email</li><li>API Key</li></ul><h2 id="ماذا-يفعل-هذا-الإعداد؟" tabindex="-1">ماذا يفعل هذا الإعداد؟ <a class="header-anchor" href="#ماذا-يفعل-هذا-الإعداد؟" aria-label="Permalink to &quot;ماذا يفعل هذا الإعداد؟&quot;">​</a></h2><p>قد يخزّن Cloudflare روابط الصور العامة في الكاش.</p><p>الكاش يجعل عرض الصور أسرع، لكنه قد يُبقي المحتوى القديم ظاهرًا لبعض الوقت بعد حذف ملف أو حجبه أو استبداله أو نقله.</p><p>بعد ضبط بيانات Cloudflare API، يحاول ImgBed تنظيف كاش Cloudflare المرتبط عند اكتمال هذه العمليات.</p><p>هذا مفيد عندما:</p><ul><li>تحذف صورة وتريد أن يتوقف الرابط العام عن العمل بأسرع وقت.</li><li>تحجب صورة وتريد منع الزوار من رؤية الملف الأصلي.</li><li>تستبدل ملفًا بالاسم نفسه وتريد أن يرى الزوار النسخة الجديدة بسرعة.</li><li>تنقل أو تعيد تسمية ملفات وتريد تحديث كاش المسارات القديمة بسرعة.</li><li>تغيّر قواعد الوصول العام وتريد تحديث كاش public gallery أو random image بسرعة.</li></ul><h2 id="ماذا-يحدث-إذا-تركته-فارغًا؟" tabindex="-1">ماذا يحدث إذا تركته فارغًا؟ <a class="header-anchor" href="#ماذا-يحدث-إذا-تركته-فارغًا؟" aria-label="Permalink to &quot;ماذا يحدث إذا تركته فارغًا؟&quot;">​</a></h2><p>سيستمر ImgBed في العمل بشكل طبيعي دون هذا الإعداد.</p><p>الفرق الوحيد أن ImgBed لن ينظف كاش Cloudflare CDN بشكل نشط. قد يواصل الزوار رؤية المحتوى القديم إلى أن تنتهي صلاحية كاش Cloudflare طبيعيًا.</p><h2 id="كيف-تجد-zone-id؟" tabindex="-1">كيف تجد Zone ID؟ <a class="header-anchor" href="#كيف-تجد-zone-id؟" aria-label="Permalink to &quot;كيف تجد Zone ID؟&quot;">​</a></h2><p>Zone ID هو معرّف Cloudflare Zone للموقع الذي يستخدمه نطاق ImgBed.</p><ol><li>سجّل الدخول إلى Cloudflare dashboard.</li><li>افتح الموقع الذي يحتوي نطاق ImgBed.</li><li>ابحث عن <code>Zone ID</code> في صفحة overview.</li><li>انسخه إلى حقل <code>Zone ID</code> في ImgBed.</li></ol><p>هذا هو Zone ID الخاص بالموقع، وليس account ID.</p><h2 id="account-email" tabindex="-1">Account Email <a class="header-anchor" href="#account-email" aria-label="Permalink to &quot;Account Email&quot;">​</a></h2><p>أدخل البريد الذي تستخدمه للدخول إلى Cloudflare.</p><p>يجب أن يطابق API Key الذي ستدخله أدناه.</p><h2 id="api-key" tabindex="-1">API Key <a class="header-anchor" href="#api-key" aria-label="Permalink to &quot;API Key&quot;">​</a></h2><p>أدخل Cloudflare Global API Key.</p><ol><li>سجّل الدخول إلى Cloudflare dashboard.</li><li>افتح ملفك الشخصي.</li><li>انتقل إلى صفحة API Tokens.</li><li>ابحث عن <code>Global API Key</code>.</li><li>اعرضه وانسخه.</li><li>الصقه في حقل <code>API Key</code> في ImgBed.</li></ol><p><img src="'+l+'" alt="عرض global API key" loading="lazy"></p><h2 id="متى-يبدأ-العمل؟" tabindex="-1">متى يبدأ العمل؟ <a class="header-anchor" href="#متى-يبدأ-العمل؟" aria-label="Permalink to &quot;متى يبدأ العمل؟&quot;">​</a></h2><p>بعد ملء الحقول احفظ الإعدادات.</p><p>ستحاول تغييرات الملفات المستقبلية تنظيف كاش Cloudflare تلقائيًا. العمليات السابقة لا تُنظف بأثر رجعي. إذا حذفت أو استبدلت ملفًا قبل ضبط هذا الإعداد، فانتظر انتهاء كاش Cloudflare أو نظفه يدويًا من Cloudflare.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="هل-هو-مطلوب؟" tabindex="-1">هل هو مطلوب؟ <a class="header-anchor" href="#هل-هو-مطلوب؟" aria-label="Permalink to &quot;هل هو مطلوب؟&quot;">​</a></h3><p>لا.</p><p>إذا كان نطاقك لا يستخدم Cloudflare، أو لا يهمك تأخير كاش CDN، يمكنك تركه فارغًا.</p><h3 id="هل-تكسر-البيانات-الخاطئة-الرفع؟" tabindex="-1">هل تكسر البيانات الخاطئة الرفع؟ <a class="header-anchor" href="#هل-تكسر-البيانات-الخاطئة-الرفع؟" aria-label="Permalink to &quot;هل تكسر البيانات الخاطئة الرفع؟&quot;">​</a></h3><p>غالبًا لا.</p><p>البيانات الخاطئة تمنع ImgBed فقط من تنظيف كاش Cloudflare. الرفع والوصول العادي للملفات يجب أن يستمرا.</p><h3 id="لماذا-ما-زالت-الصورة-المحذوفة-تفتح؟" tabindex="-1">لماذا ما زالت الصورة المحذوفة تفتح؟ <a class="header-anchor" href="#لماذا-ما-زالت-الصورة-المحذوفة-تفتح؟" aria-label="Permalink to &quot;لماذا ما زالت الصورة المحذوفة تفتح؟&quot;">​</a></h3><p>السبب الأكثر شيوعًا أن Cloudflare ما زال يحتفظ بالملف القديم في الكاش.</p><p>مع بيانات Cloudflare API الصحيحة، ينظف ImgBed كاش الرابط المرتبط عند حذف الملف.</p><h3 id="لماذا-أرى-الصورة-القديمة-بعد-استبدال-ملف؟" tabindex="-1">لماذا أرى الصورة القديمة بعد استبدال ملف؟ <a class="header-anchor" href="#لماذا-أرى-الصورة-القديمة-بعد-استبدال-ملف؟" aria-label="Permalink to &quot;لماذا أرى الصورة القديمة بعد استبدال ملف؟&quot;">​</a></h3><p>هذا غالبًا بسبب كاش CDN أيضًا.</p><p>بعد ضبط هذا الإعداد، يحاول ImgBed تنظيف كاش الرابط القديم عند الكتابة فوق ملف بالاسم نفسه.</p>',44)])])}const P=o(d,[["render",n]]);export{b as __pageData,P as default};
